#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=10005,mod=9997;
int ans;
vector<int> g[maxn];
int in[maxn];
bool toposort(int n,int m) {
	vector<int> l;
	queue<int> s;
	for(int i=1; i<=n; i++) {
		if(in[i]==0) {
			s.push(i);
		}
	}
	while(!s.empty()) {
		int u=s.front();
		s.pop();
		l.push_back(u);
		for(auto v:g[u]) {
			if(--in[v]==0) {
				s.push(v);
			}
		}
	}
	if (l.size()==n) {
		return 1;
	}
	return 0;
}
int ksm(int n,int m) {
	int s=1;
	while(m) {
		if(m&1) {
			s=s*n%mod;
		}
		n=n*n%mod;
		m>>=1;
	}
	return s;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,m,k;
	cin>>n>>m>>k;
	for(int i=1; i<=m; i++) {
		int u,v;
		cin>>u>>v;
		g[u].emplace_back(v);
		in[v]++;
	}
	bool ok=toposort(n,m);
	if(ok) {
		cout<<"Yes";
	} else {
		cout<<"No";
	}
	cout<<"\n";
	if(ok) {
		cout<<ksm(2,k);
	}else{
		cout<<k*k;
	}
	return 0;
}
